[
  {
    "title": "ALLBUS – German General Social Survey (GSS) Germany",
    "url": "https://www.gesis.org/en/allbus",
    "description": "National face-to-face survey using a standardized questionnaire; covers community/urban–rural life, cultural activities and participation, political behavior and attitudes, government/political systems, and housing across multiple waves."
  },
  {
    "title": "Eurobarometer Data Service (GESIS)",
    "url": "https://www.gesis.org/en/eurobarometer-data-service",
    "description": "Cross-national face-to-face public opinion surveys with standardized instruments; includes modules on political behavior and attitudes, government and political systems, culture, and community/urban–rural issues."
  },
  {
    "title": "European Values Study (EVS) at GESIS",
    "url": "https://www.gesis.org/en/evs",
    "description": "Cross-national face-to-face values surveys using standardized questionnaires; covers culture, political attitudes and behavior, social/community life, and related domains with German participation."
  },
  {
    "title": "International Social Survey Programme (ISSP) at GESIS",
    "url": "https://www.gesis.org/en/issp",
    "description": "Annual cross-national modules often implemented via face-to-face standardized interviews in Germany; themes include government/citizenship, culture/leisure, social/community life, and living conditions relevant to housing."
  },
  {
    "title": "European Social Survey (ESS) – GESIS",
    "url": "https://www.gesis.org/en/ess",
    "description": "Biennial face-to-face survey with a standardized questionnaire; topics include political behavior and attitudes, trust in government and institutions, culture, social/community life, and urban–rural differences."
  },
  {
    "title": "German Longitudinal Election Study (GLES) – GESIS",
    "url": "https://www.gesis.org/en/gles",
    "description": "German election study program; includes face-to-face post-election surveys with standardized questionnaires on political behavior and attitudes, parties, and perceptions of government."
  }
]
